import React, { useState, useEffect } from 'react';
import DisplayStockData from './Stock';
import './Stock.css'
import mid from '../mid.png';

function View() {
  const [symbols, setSymbols] = useState([]);
  const [stockData, setStockData] = useState([]);
  const stocks = ['NIFTY', 'NIFTYIT', 'BANKNIFTY', 'GMRINFRA', 'IDEA', 'IEX', 'BANDHANBNK', 'LAURUSLABS', 'DELTACORP', 'GNFC', 'HEROMOTOCO', 'INTELLECT', 'BALRAMCHIN', 'VEDL', 'COALINDIA', 'CANFINHOME', 'CHAMBLFERT', 'GLENMARK', 'BAJAJ-AUTO', 'POLYCAB', 'AMBUJACEM', 'RAIN', 'MARUTI', 'CROMPTON', 'BSOFT', 'ACC', 'PFC', 'M&MFIN', 'CHOLAFIN', 'SHRIRAMFIN', 'PETRONET', 'RBLBANK', 'GRANULES', 'IBULHSGFIN', 'DIVISLAB', 'TATAPOWER', 'L&TFH', 'LTTS', 'CUB', 'ONGC', 'EICHERMOT', 'BAJFINANCE', 'UPL', 'BHARTIARTL', 'PNB', 'NTPC', 'LICHSGFIN', 'GODREJPROP', 'HINDCOPPER', 'RECLTD', 'DIXON', 'NATIONALUM', 'SAIL', 'BAJAJFINSV', 'HDFCAMC', 'ASHOKLEY', 'BIOCON', 'HCLTECH', 'DLF', 'EXIDEIND', 'HDFCLIFE', 'M&M', 'TATACONSUM', 'SBICARD', 'INDUSINDBK', 'IDFC', 'MANAPPURAM', 'IDFCFIRSTB', 'COLPAL', 'CANBK', 'ICICIGI', 'PEL', 'INDIACEM', 'MOTHERSON', 'APOLLOTYRE', 'DRREDDY', 'TITAN', 'ICICIBANK', 'TATAMOTORS', 'WIPRO', 'SUNTV', 'AXISBANK', 'WHIRLPOOL', 'LALPATHLAB', 'SIEMENS', 'ZEEL', 'KOTAKBANK', 'TVSMOTOR', 'COFORGE', 'ABFRL', 'BATAINDIA', 'ICICIPRULI', 'VOLTAS', 'ABBOTINDIA', 'ASIANPAINT', 'UBL', 'METROPOLIS', 'FEDERALBNK', 'TORNTPHARM', 'ABB', 'INDUSTOWER', 'TATACHEM', 'MRF', 'RAMCOCEM', 'COROMANDEL', 'AARTIIND', 'SBIN', 'SBILIFE', 'OFSS', 'GUJGASLTD', 'GAIL', 'MFSL', 'TECHM', 'MPHASIS', 'ULTRACEMCO', 'BANKBARODA', 'SHREECEM', 'ABCAPITAL', 'LT', 'ASTRAL', 'HONAUT', 'HDFC', 'AUROPHARMA', 'BOSCHLTD', 'CONCOR', 'HAVELLS', 'LUPIN', 'MUTHOOTFIN', 'DALBHARAT', 'ZYDUSLIFE', 'DABUR', 'HDFCBANK', 'JINDALSTEL', 'OBEROIRLTY', 'RELIANCE', 'NMDC', 'IPCALAB', 'BHARATFORG', 'NESTLEIND', 'MARICO', 'INDIAMART', 'IRCTC', 'TATACOMM', 'TCS', 'HAL', 'BALKRISIND', 'LTIM', 'BHEL', 'IOC', 'TATASTEEL', 'GODREJCP', 'PAGEIND', 'SUNPHARMA', 'ALKEM', 'ADANIPORTS', 'GRASIM', 'BRITANNIA', 'MCX', 'POWERGRID', 'MCDOWELL-N', 'INDIGO', 'BEL', 'ATUL', 'JKCEMENT', 'BERGEPAINT', 'HINDALCO', 'INDHOTEL', 'JSWSTEEL', 'JUBLFOOD', 'HINDUNILVR', 'NAUKRI', 'CIPLA', 'ESCORTS', 'ITC', 'NAVINFLUOR', 'PIDILITIND', 'PVR', 'INFY', 'SYNGENE', 'CUMMINSIND', 'TRENT', 'PERSISTENT', 'IGL', 'PIIND', 'APOLLOHOSP', 'DEEPAKNTR', 'ADANIENT', 'SRF', 'AUBANK', 'BPCL', 'HINDPETRO', 'MGL'];
  const [selectedStock, setSelectedStock] = useState(null);

  function handleStockClick(stock) {
    setSelectedStock(stock);
  }

  const handleAddSymbol = async symbol => {
    if (symbols.length < 9 && !symbols.includes(symbol)) {
      const response = await fetch(`http://127.0.0.1:8000/${symbol}/`);
      const data = await response.json();
      if (data.hasOwnProperty('error')) {
        alert(data.error);
        return;
      }
      setSymbols([...symbols, symbol]);
    } else {
      alert("Symbol already entered or maximum limit reached (9)");
    }
  };
  

  const handleRemoveSymbol = symbol => {
    setSymbols(symbols.filter(item => item !== symbol));
    setStockData(stockData.filter(item => item.symbol !== symbol));
  };  
  const [sensexData, setSensexData] = useState({});
  const arrow = sensexData.change > 0 ? '\u25B2' : '\u25BC';
  useEffect(() => {
    const fetchSensexData = async () => {
      const response = await fetch('http://127.0.0.1:8000/BSE/');
      const data = await response.json();
      setSensexData(data);
    };
    fetchSensexData();
  }, []);
  
  const [sensexDatai, setSensexDatai] = useState({});
  const arrowi = sensexDatai.change > 0 ? '\u25B2' : '\u25BC';
  useEffect(() => {
    const fetchSensexDatai = async () => {
      const response = await fetch('http://127.0.0.1:8000/INFY/');
      const data = await response.json();
      setSensexDatai(data);
    };
    fetchSensexDatai();
  }, []);
  


  useEffect(() => {
    const fetchData = async () => {
      if (!symbols.length) {
        return;
      }
      const urls = symbols.map(symbol => `http://127.0.0.1:8000/${symbol}/`);
      const promises = urls.map(url => fetch(url).then(response => response.json()));
      const data = await Promise.all(promises);
      setStockData(data);
    };
    fetchData();
  }, [symbols]);

  useEffect(() => {
    let sockets = [];
    if (stockData.length) {
      stockData.forEach(data => {
        const socket = new WebSocket(`ws://127.0.0.1:8000/ws/stock/${data.symbol}/`);
        socket.onmessage = event => {
          const updatedData = JSON.parse(event.data);
          setStockData(prevData => prevData.map(item => (item.symbol === updatedData.symbol ? updatedData : item)));
        };
        sockets.push(socket);
      });
    }
    return () => {
      sockets.forEach(socket => socket.close());
    };
  }, [stockData]);

  return (
    <div className='f19'>
      <div>
        <div className="info-container">
          {stockData.map(data => (
            <div key={data.symbol} >
              <DisplayStockData stockData={data} />
              {/* <button onClick={() => handleRemoveSymbol(data.symbol)}>&#10799;</button> */}
            </div>
          ))}
        </div>
      </div>
      <div className='grid'>
        <form
          onSubmit={event => {
            event.preventDefault();
            const symbol = event.target.symbol.value.toUpperCase();
            handleAddSymbol(symbol);
            event.target.symbol.value = '';
          }}
        >
          <div className='two item'>
            <input className='f19' type="text" placeholder='enter stock'  name="symbol"></input>
            {/* <button type="submit" >+</button> */}
          </div>
        </form>
        {symbols.length > 0 ? (
          <div className='four item'>
            <div className="circles-grid">
              {[...Array(9)].map((_, i) => (
                <div
                  key={i}
                  className={`circle ${i < symbols.length ? "black" : "red"}`}
                ></div>
              ))}
            </div>
            <div className="symbol-count">
            <span >{symbols.length}</span> / 9 &nbsp;
              <button className='but f19' onClick={() => {
                setSymbols([]);
                setStockData([]);
              }}>X</button>
              
            </div>
          </div>
        ) : (
          <div className='four item'>
            <div className="circles-grid">
              {[...Array(9)].map((_, i) => (
                <div key={i} className="circle red"></div>
              ))}
            </div>
            <div className="symbol-count">
            <span >{symbols.length}</span> / 9 &nbsp;
            </div>
          </div>
        )}
        <div className='six  item in-grid iga'>
          <div className='ione'>
            {sensexData && (
              <>
                <div>{sensexData.symbol}</div>
                <div>{sensexData.price}</div>
                <div>{arrow}{sensexData.pChange}</div>
                <div>{sensexData.change}</div>
              </>
            )}
          </div>
          <div className='itwo'>
            {sensexDatai && (
              <>
                <div>{sensexDatai.symbol}</div>
                <div>{sensexDatai.price}</div>
                <div>{arrowi}{sensexDatai.pChange}</div>
                <div>{sensexDatai.change}</div>
              </>
            )}
          </div>
        </div>
        <div className='three element item'>
          {stocks.map(stock => (
            <a className='opt' key={stock} onClick={() => handleStockClick(stock)}>{stock}</a>
          ))}
        </div>
        <stock symbol={selectedStock} />

        <div className='th item'>
          <img src={mid} width="200" height="415" alt="mid" />;
        </div>
      </div>  
    </div>
  );
}

export default View;











































































